DROP TABLE IF EXISTS `User`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `User` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `username` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `password` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'USER',
  `permissions` text COLLATE utf8mb4_unicode_ci,
  `creditBalance` decimal(10,2) NOT NULL DEFAULT '0.00',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `image` text COLLATE utf8mb4_unicode_ci,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pointBalance` int NOT NULL DEFAULT '0',
  `lifetimePoints` int NOT NULL DEFAULT '0',
  `totalTopup` decimal(10,2) NOT NULL DEFAULT '0.00',
  `emailVerified` tinyint(1) NOT NULL DEFAULT '0',
  `firstName` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `firstNameEn` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lastName` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lastNameEn` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phoneVerified` tinyint(1) NOT NULL DEFAULT '0',
  `shipAddress` text COLLATE utf8mb4_unicode_ci,
  `shipDistrict` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipFullName` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipPhone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipPostalCode` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipProvince` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxAddress` text COLLATE utf8mb4_unicode_ci,
  `taxDistrict` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxFullName` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxPhone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxPostalCode` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxProvince` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipSubdistrict` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `taxSubdistrict` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `User_username_key` (`username`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
